// // This module registers the input Data0 on the falling edge of the Clock signal, and updates the output Q0 only when the Enable signal is low.
module top_module(Clock, Enable,Data0,Q0);input Clock, Enable; 
 input Data0; 
 output reg Q0; 
 always @(posedge Clock) 
  if (Enable) 
  Q0 <= Data0; 
 endmodule
